const animal = { speak() { return this.sound; } };
const dog = Object.create(animal);
dog.sound = 'woof';

console.log(dog.speak());                       // 'woof' (found on animal)
console.log(dog.hasOwnProperty('speak'));       // false (inherited)
console.log(Object.getPrototypeOf(dog) === animal); // true

animal.speak = function () { return 'overridden:' + this.sound; };
console.log(dog.speak());                       // 'overridden:woof'

const wait = (ms, v) => new Promise(r => setTimeout(() => r(v), ms));

async function run() {
  const start = Date.now();
  // parallel: both timers run together
  const [a, b] = await Promise.all([wait(50, 'A'), wait(50, 'B')]);
  console.log(a, b, 'in ~', Date.now() - start, 'ms');
}
run();

const add = a => b => c => a + b + c;
console.log(add(1)(2)(3)); // 6

function curry(fn) {
  return function curried(...args) {
    return args.length >= fn.length
      ? fn(...args)
      : (...more) => curried(...args, ...more);
  };
}
const sum = curry((a, b, c) => a + b + c);
console.log(sum(1, 2)(3)); // 6
console.log(sum(1)(2, 3)); // 6

let a;                       // declared, not assigned
const obj = { name: "Ada" };
console.log(a);              // undefined
console.log(obj.age);       // undefined (missing property)
console.log(typeof undefined, typeof null); // "undefined" "object" (legacy bug)

console.log(null == undefined);   // true  (loose)
console.log(null === undefined);  // false (strict)

// default params trigger on undefined, NOT null
function greet(name = "guest") { return "Hi " + name; }
console.log(greet(undefined)); // "Hi guest"
console.log(greet(null));       // "Hi null"

const x = null;
