console.log(name, city, role);          // Ada London guest

// array: skip holes, default, rest
const [first, , third = 0, ...rest] = [10, 20, 30, 40, 50];
console.log(first, third, rest);        // 10 30 [40, 50]

// swap with no temp variable
let a = 1, b = 2;
[a, b] = [b, a];
console.log(a, b);                       // 2 1

function* naturals() {
  let n = 1;
  while (true) yield n++;        // infinite, but lazy
}
const it = naturals();
console.log(it.next().value, it.next().value); // 1 2

function* take(gen, k) {
  for (const v of gen) { if (k-- <= 0) return; yield v; }
}
console.log([...take(naturals(), 5)]); // [1,2,3,4,5]

function memoize(fn) {
  const cache = new Map();
  return (...args) => {
    const key = JSON.stringify(args);
    if (cache.has(key)) { console.log('hit', key); return cache.get(key); }
    const val = fn(...args);
    cache.set(key, val);
    return val;
  };
}
const slowSquare = memoize(n => n * n);
console.log(slowSquare(8)); // 64 (computed)
console.log(slowSquare(8)); // hit [8] -> 64 (cached)

const nums = [1, 2, 3];

const doubled = nums.map((n) => n * 2);
console.log(doubled);                 // [2, 4, 6]

const result = nums.forEach((n) => n * 2);
console.log(result);                  // undefined — nothing returned

// forEach for side effects
let sum = 0;
nums.forEach((n) => { sum += n; });
console.log(sum);                     // 6

// map chains; forEach can't
console.log(nums.map((n) => n + 1).filter((n) => n > 2)); // [3, 4]

function intro(greeting, punc) {
  return greeting + ', ' + this.name + punc;
}
const person = { name: 'Ada' };

console.log(intro.call(person, 'Hi', '!'));   // 'Hi, Ada!'
console.log(intro.apply(person, ['Hey', '.'])); // 'Hey, Ada.'

const boundHi = intro.bind(person, 'Hello');
console.log(boundHi('?'));                     // 'Hello, Ada?'

const user = { name: "", settings: null };

// optional chaining — no throw on missing links
console.log(user?.settings?.theme);   // undefined
console.log(user?.profile?.bio);       // undefined

// ?? keeps valid falsy values; || would clobber them
console.log(user.name ?? "Guest");     // ""      (empty string is valid)
console.log(user.name || "Guest");     // "Guest" (|| treats "" as empty)
console.log(0 ?? 10, 0 || 10);          // 0 10

// guard a method call + array index
console.log(user.greet?.());            // undefined (no error)
console.log([1, 2]?.[5]);               // undefined

const nums = [1, 2, 3, 4];
