const safe = new Proxy({}, {
  get: (t, k) => (k in t ? t[k] : `<missing:${String(k)}>`),
  set: (t, k, v) => {
    if (k === 'age' && typeof v !== 'number') throw new TypeError('age must be a number');
    t[k] = v; return true;
  },
});
safe.name = 'Ada';
console.log(safe.name, safe.unknown); // 'Ada' '<missing:unknown>'
try { safe.age = 'x'; } catch (e) { console.log(e.message); }

function Point(x, y) { this.x = x; this.y = y; }
Point.prototype.sum = function () { return this.x + this.y; };

function myNew(Ctor, ...args) {
  const obj = Object.create(Ctor.prototype);
  const ret = Ctor.apply(obj, args);
  return (ret && typeof ret === 'object') ? ret : obj;
}
const p = myNew(Point, 3, 4);
console.log(p.x, p.y, p.sum());          // 3 4 7
console.log(p instanceof Point);          // true

const compose = (...fns) => (x) => fns.reduceRight((acc, fn) => fn(acc), x);
const pipe = (...fns) => (x) => fns.reduce((acc, fn) => fn(acc), x);

const double = (n) => n * 2;
const inc = (n) => n + 1;

console.log(compose(double, inc)(5)); // double(inc(5)) = 12  (right→left)
console.log(pipe(double, inc)(5));     // inc(double(5))  = 11  (left→right)

// a readable data pipeline with pipe
const shout = pipe((s) => s.trim(), (s) => s.toUpperCase(), (s) => s + "!");
console.log(shout("  hello "));         // "HELLO!"

